import{_ as t,c as r,o as d,a1 as n}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Frameworks: 40+ Deployment-Optionen | Agent Skills","description":"Sehen Sie die vollständige Liste der von Agent Skills Vercel Deploy unterstützten Frameworks. Deckt 40+ Frontend-Frameworks ab, einschließlich React, Vue, Svelte, Angular. Enthält Erkennungsprinzipien.","frontmatter":{"title":"Frameworks: 40+ Deployment-Optionen | Agent Skills","sidebarTitle":"Frameworks","subtitle":"Frameworks: 40+ Deployment-Optionen","description":"Sehen Sie die vollständige Liste der von Agent Skills Vercel Deploy unterstützten Frameworks. Deckt 40+ Frontend-Frameworks ab, einschließlich React, Vue, Svelte, Angular. Enthält Erkennungsprinzipien.","tags":["Frameworks","Deployment","Kompatibilität","Referenz"],"prerequisite":[]},"headers":[],"relativePath":"de/vercel-labs/agent-skills/appendix/frameworks/index.md","filePath":"de/vercel-labs/agent-skills/appendix/frameworks/index.md"}'),o={name:"de/vercel-labs/agent-skills/appendix/frameworks/index.md"};function a(s,e,i,c,l,h){return d(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="unterstutzte-framework-liste" tabindex="-1">Unterstützte Framework-Liste <a class="header-anchor" href="#unterstutzte-framework-liste" aria-label="Permalink to &quot;Unterstützte Framework-Liste&quot;">​</a></h1><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Vollständige Liste der von Vercel Deploy unterstützten Frameworks kennen (45+)</li><li>Verstehen Sie das Funktionsprinzip der Framework-Erkennung</li><li>Beurteilen, ob Ihr Projekt Ein-Klick-Deployment unterstützt</li><li>Prioritätsregeln der Framework-Erkennung ansehen</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Vercel Deploy-Skill scannt die <code>dependencies</code>- und <code>devDependencies</code>-Abhängigkeiten der Datei <code>package.json</code> Ihres Projekts, prüft逐一 vordefinierte Framework-Merkmalspaketnamen, um zu beurteilen, welches Framework das Projekt verwendet.</p><p><strong>Erkennung in Prioritätsreihenfolge</strong>: Vom spezifischsten Framework zum allgemeinsten, um Fehleinschätzungen zu vermeiden. Zum Beispiel:</p><ol><li>Prüfen auf <code>next</code> → Übereinstimmung mit Next.js</li><li>Selbst wenn <code>react</code> gleichzeitig vorhanden ist, wird es als Next.js priorisiert erkannt</li></ol><div class="tip custom-block"><p class="custom-block-title">Erkennungsbereich</p><p>Die Erkennung prüft gleichzeitig <code>dependencies</code> und <code>devDependencies</code>, daher werden auch Frameworks erkannt, die nur als Entwicklungsabhängigkeit installiert wurden.</p></div><h2 id="vollstandige-framework-liste" tabindex="-1">Vollständige Framework-Liste <a class="header-anchor" href="#vollstandige-framework-liste" aria-label="Permalink to &quot;Vollständige Framework-Liste&quot;">​</a></h2><h3 id="react-okosystem" tabindex="-1">React-Ökosystem <a class="header-anchor" href="#react-okosystem" aria-label="Permalink to &quot;React-Ökosystem&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>Next.js</strong></td><td><code>next</code></td><td><code>nextjs</code></td></tr><tr><td><strong>Gatsby</strong></td><td><code>gatsby</code></td><td><code>gatsby</code></td></tr><tr><td><strong>Remix</strong></td><td><code>@remix-run/</code></td><td><code>remix</code></td></tr><tr><td><strong>React Router</strong></td><td><code>@react-router/</code></td><td><code>react-router</code></td></tr><tr><td><strong>Blitz</strong></td><td><code>blitz</code></td><td><code>blitzjs</code></td></tr><tr><td><strong>Create React App</strong></td><td><code>react-scripts</code></td><td><code>create-react-app</code></td></tr><tr><td><strong>Ionic React</strong></td><td><code>@ionic/react</code></td><td><code>ionic-react</code></td></tr><tr><td><strong>Preact</strong></td><td><code>preact</code></td><td><code>preact</code></td></tr></tbody></table><h3 id="vue-okosystem" tabindex="-1">Vue-Ökosystem <a class="header-anchor" href="#vue-okosystem" aria-label="Permalink to &quot;Vue-Ökosystem&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>Nuxt</strong></td><td><code>nuxt</code></td><td><code>nuxtjs</code></td></tr><tr><td><strong>VitePress</strong></td><td><code>vitepress</code></td><td><code>vitepress</code></td></tr><tr><td><strong>VuePress</strong></td><td><code>vuepress</code></td><td><code>vuepress</code></td></tr><tr><td><strong>Gridsome</strong></td><td><code>gridsome</code></td><td><code>gridsome</code></td></tr></tbody></table><h3 id="svelte-okosystem" tabindex="-1">Svelte-Ökosystem <a class="header-anchor" href="#svelte-okosystem" aria-label="Permalink to &quot;Svelte-Ökosystem&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>SvelteKit</strong></td><td><code>@sveltejs/kit</code></td><td><code>sveltekit-1</code></td></tr><tr><td><strong>Svelte</strong></td><td><code>svelte</code></td><td><code>svelte</code></td></tr><tr><td><strong>Sapper</strong> (legacy)</td><td><code>sapper</code></td><td><code>sapper</code></td></tr></tbody></table><h3 id="angular" tabindex="-1">Angular <a class="header-anchor" href="#angular" aria-label="Permalink to &quot;Angular&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>Angular</strong></td><td><code>@angular/core</code></td><td><code>angular</code></td></tr><tr><td><strong>Ionic Angular</strong></td><td><code>@ionic/angular</code></td><td><code>ionic-angular</code></td></tr></tbody></table><h3 id="statische-site-generatoren" tabindex="-1">Statische Site-Generatoren <a class="header-anchor" href="#statische-site-generatoren" aria-label="Permalink to &quot;Statische Site-Generatoren&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>Astro</strong></td><td><code>astro</code></td><td><code>astro</code></td></tr><tr><td><strong>Docusaurus</strong></td><td><code>@docusaurus/core</code></td><td><code>docusaurus-2</code></td></tr><tr><td><strong>Hexo</strong></td><td><code>hexo</code></td><td><code>hexo</code></td></tr><tr><td><strong>Eleventy</strong></td><td><code>@11ty/eleventy</code></td><td><code>eleventy</code></td></tr><tr><td><strong>RedwoodJS</strong></td><td><code>@redwoodjs/</code></td><td><code>redwoodjs</code></td></tr></tbody></table><h3 id="node-js-backend-frameworks" tabindex="-1">Node.js-Backend-Frameworks <a class="header-anchor" href="#node-js-backend-frameworks" aria-label="Permalink to &quot;Node.js-Backend-Frameworks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>Express</strong></td><td><code>express</code></td><td><code>express</code></td></tr><tr><td><strong>NestJS</strong></td><td><code>@nestjs/core</code></td><td><code>nestjs</code></td></tr><tr><td><strong>Hono</strong></td><td><code>hono</code></td><td><code>hono</code></td></tr><tr><td><strong>Fastify</strong></td><td><code>fastify</code></td><td><code>fastify</code></td></tr><tr><td><strong>Elysia</strong></td><td><code>elysia</code></td><td><code>elysia</code></td></tr><tr><td><strong>h3</strong></td><td><code>h3</code></td><td><code>h3</code></td></tr><tr><td><strong>Nitro</strong></td><td><code>nitropack</code></td><td><code>nitro</code></td></tr></tbody></table><h3 id="andere-frameworks" tabindex="-1">Andere Frameworks <a class="header-anchor" href="#andere-frameworks" aria-label="Permalink to &quot;Andere Frameworks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>SolidStart</strong></td><td><code>@solidjs/start</code></td><td><code>solidstart-1</code></td></tr><tr><td><strong>Ember</strong></td><td><code>ember-cli</code>, <code>ember-source</code></td><td><code>ember</code></td></tr><tr><td><strong>Dojo</strong></td><td><code>@dojo/framework</code></td><td><code>dojo</code></td></tr><tr><td><strong>Polymer</strong></td><td><code>@polymer/</code></td><td><code>polymer</code></td></tr><tr><td><strong>Stencil</strong></td><td><code>@stencil/core</code></td><td><code>stencil</code></td></tr><tr><td><strong>UmiJS</strong></td><td><code>umi</code></td><td><code>umijs</code></td></tr><tr><td><strong>Saber</strong></td><td><code>saber</code></td><td><code>saber</code></td></tr><tr><td><strong>Sanity</strong></td><td><code>sanity</code>, <code>@sanity/</code></td><td><code>sanity</code> oder <code>sanity-v3</code></td></tr><tr><td><strong>Storybook</strong></td><td><code>@storybook/</code></td><td><code>storybook</code></td></tr><tr><td><strong>Hydrogen</strong> (Shopify)</td><td><code>@shopify/hydrogen</code></td><td><code>hydrogen</code></td></tr><tr><td><strong>TanStack Start</strong></td><td><code>@tanstack/start</code></td><td><code>tanstack-start</code></td></tr></tbody></table><h3 id="build-tools" tabindex="-1">Build-Tools <a class="header-anchor" href="#build-tools" aria-label="Permalink to &quot;Build-Tools&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Framework</th><th>Erkennungsabhängigkeit</th><th>Rückgabewert</th></tr></thead><tbody><tr><td><strong>Vite</strong></td><td><code>vite</code></td><td><code>vite</code></td></tr><tr><td><strong>Parcel</strong></td><td><code>parcel</code></td><td><code>parcel</code></td></tr></tbody></table><h3 id="statische-html-projekte" tabindex="-1">Statische HTML-Projekte <a class="header-anchor" href="#statische-html-projekte" aria-label="Permalink to &quot;Statische HTML-Projekte&quot;">​</a></h3><p>Wenn Ihr Projekt <strong>keine</strong> <code>package.json</code> hat (reine statische Website), gibt die Framework-Erkennung <code>null</code> zurück.</p><p>Das Deployment-Skript behandelt dies intelligent:</p><ul><li>Automatische Erkennung von <code>.html</code>-Dateien im Stammverzeichnis</li><li>Wenn nur eine <code>.html</code>-Datei vorhanden ist und diese nicht <code>index.html</code> heißt, wird sie automatisch in <code>index.html</code> umbenannt</li><li>Direktes Hosting als statische Website auf Vercel</li></ul><h2 id="framework-erkennungsprinzip" tabindex="-1">Framework-Erkennungsprinzip <a class="header-anchor" href="#framework-erkennungsprinzip" aria-label="Permalink to &quot;Framework-Erkennungsprinzip&quot;">​</a></h2><h3 id="erkennungsablauf" tabindex="-1">Erkennungsablauf <a class="header-anchor" href="#erkennungsablauf" aria-label="Permalink to &quot;Erkennungsablauf&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>package.json lesen</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>dependencies und devDependencies scannen</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>In Prioritätsreihenfolge vordefinierte Paketnamen abgleichen</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Erste Übereinstimmung gefunden → Rückgabe des entsprechenden Framework-Identifikators</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Keine Übereinstimmung gefunden → Rückgabe von null (statisches HTML-Projekt)</span></span></code></pre></div><h3 id="erkennungsreihenfolge" tabindex="-1">Erkennungsreihenfolge <a class="header-anchor" href="#erkennungsreihenfolge" aria-label="Permalink to &quot;Erkennungsreihenfolge&quot;">​</a></h3><p>Die Erkennung ist nach der Spezifität von Frameworks sortiert, <strong>bevorzugt spezifischere Frameworks</strong>:</p><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Agent Skills Vercel Deploy-Funktion unterstützt <strong>45+ Frameworks</strong>, deckt alle gängigen Frontend-Technologiestacks ab:</p><p><strong>Kernwerte</strong>:</p><ul><li>✅ Breite Framework-Unterstützung, React/Vue/Svelte/Angular vollständig abgedeckt</li><li>✅ Intelligente Framework-Erkennung, automatische Erkennung des Projekttyps</li><li>✅ Unterstützung statischer HTML-Projekte, Deployment ohne Abhängigkeiten</li><li>✅ Open-Source, erweiterbar für neue Frameworks</li></ul><p><strong>Erkennungsprinzip</strong>:</p><ul><li>Scan der <code>dependencies</code> und <code>devDependencies</code> von package.json</li><li>Abgleich vordefinierter Framework-Merkmalspaketnamen in Prioritätsreihenfolge</li><li>Rückgabe des entsprechenden Framework-Identifikators zur Verwendung durch Vercel</li></ul><p><strong>Nächste Schritte</strong>: Lesen Sie das <a href="./../../platforms/vercel-deploy/">Vercel Ein-Klick-Deployment-Tutorial</a>, um zu erfahren, wie Sie diese Funktion verwenden.</p><hr><h2 id="anhang-quellcodereferenz" tabindex="-1">Anhang: Quellcodereferenz <a class="header-anchor" href="#anhang-quellcodereferenz" aria-label="Permalink to &quot;Anhang: Quellcodereferenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcodepositionen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Funktion</strong>:</p><ul><li><code>detect_framework()</code>: Erkennt 45+ Frameworks aus package.json (11-156 Zeilen)</li></ul></details>`,44)])])}const u=t(o,[["render",a]]);export{k as __pageData,u as default};
